import os
import httpx
from pydantic import BaseModel


class APIError(Exception):
    # Raised when the upstream REST API returns a non-2xx status
    def __init__(self, status: int, body: str) -> None:
        super().__init__(f'HTTP {status}: ' + body[:200])
        self.status = status


class BaseRESTClient:
    # Reusable HTTP client base; subclass per upstream service

    def __init__(self, base_url: str, api_key: str, timeout: float = 30.0) -> None:
        self._http = httpx.Client(
            base_url=base_url,
            headers={
                "Authorization": "Bearer " + api_key,
                "Accept": "application/json",
                "Content-Type": "application/json",
            },
            timeout=httpx.Timeout(timeout, connect=5.0),
        )

    def _get(self, path: str, **params) -> dict:
        resp = self._http.get(path, params=params)
        self._check(resp)
        return resp.json()

    def _post(self, path: str, body: dict) -> dict:
        resp = self._http.post(path, json=body)
        self._check(resp)
        return resp.json()

    def _check(self, resp: httpx.Response) -> None:
        if not resp.is_success:
            raise APIError(resp.status_code, resp.text)

    def close(self) -> None:
        self._http.close()

    def __enter__(self):
        return self

    def __exit__(self, *_):
        self.close()


class SearchClient(BaseRESTClient):
    # Concrete client for the search microservice

    def search(self, query: str, limit: int = 10) -> list[dict]:
        data = self._get("/v1/search", q=query, limit=limit)
        return data["results"]

    def get_document(self, doc_id: str) -> dict:
        return self._get(f"/v1/documents/{doc_id}")
